import { useState, useEffect, useRef } from 'react';
import axios from 'axios';

const API = axios.create({ baseURL: 'http://localhost:5000/api' });

const TYPE_COLORS = {
  'Government':      '#2d6a4f',
  'Super Specialty': '#1d3557',
  'Multi Specialty': '#4895ef',
  'Private':         '#f4a261',
  'Nursing Home':    '#e63946',
  'Clinic':          '#7b2d8b',
};

const TYPE_EMOJI = {
  'Government':      '🏛️',
  'Super Specialty': '🏥',
  'Multi Specialty': '🏨',
  'Private':         '🏪',
  'Nursing Home':    '🏠',
  'Clinic':          '🩺',
};

const TRAVEL_MODES = [
  { key: 'driving-car',    label: '🚗 Drive',  osrm: 'driving'  },
  { key: 'foot-walking',   label: '🚶 Walk',   osrm: 'foot'     },
  { key: 'cycling-regular',label: '🚴 Cycle',  osrm: 'bike'     },
];

export default function NearbyHospitals() {
  const [hospitals, setHospitals] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [selectedHospital, setSelectedHospital] = useState(null);
  const [userLocation, setUserLocation] = useState(null);
  const [mapLoaded, setMapLoaded] = useState(false);
  const [search, setSearch] = useState('');
  const [typeFilter, setTypeFilter] = useState('All');
  const [emergencyOnly, setEmergencyOnly] = useState(false);
  const [loading, setLoading] = useState(true);

  // Routing state
  const [travelMode, setTravelMode] = useState('driving-car');
  const [routeInfo, setRouteInfo] = useState(null);
  const [routeLoading, setRouteLoading] = useState(false);
  const [showDirections, setShowDirections] = useState(false);
  const [steps, setSteps] = useState([]);

  const mapRef = useRef(null);
  const mapInstance = useRef(null);
  const markersRef = useRef([]);
  const routeLayerRef = useRef(null);
  const startMarkerRef = useRef(null);
  const endMarkerRef = useRef(null);

  useEffect(() => { loadHospitals(); loadLeaflet(); getUserLocation(); }, []);
  useEffect(() => { applyFilters(); }, [hospitals, search, typeFilter, emergencyOnly]);
  useEffect(() => { if (mapLoaded && mapRef.current && !mapInstance.current) initMap(); }, [mapLoaded, userLocation]);
  useEffect(() => { if (mapInstance.current && filtered.length > 0) updateMarkers(); }, [filtered, mapLoaded]);

  const loadHospitals = async () => {
    try {
      const res = await API.get('/hospitals/');
      setHospitals(res.data);
      setFiltered(res.data);
    } catch {} finally { setLoading(false); }
  };

  const loadLeaflet = () => {
    if (window.L) { setMapLoaded(true); return; }
    const link = document.createElement('link');
    link.rel = 'stylesheet';
    link.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css';
    document.head.appendChild(link);
    const script = document.createElement('script');
    script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
    script.onload = () => setMapLoaded(true);
    document.head.appendChild(script);
  };

  const getUserLocation = () => {
    if (!navigator.geolocation) { setUserLocation({ lat: 26.9124, lng: 75.7873 }); return; }
    navigator.geolocation.getCurrentPosition(
      pos => setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      () => setUserLocation({ lat: 26.9124, lng: 75.7873 })
    );
  };

  const initMap = () => {
    if (!window.L || !mapRef.current) return;
    const L = window.L;
    const center = userLocation ? [userLocation.lat, userLocation.lng] : [26.9124, 75.7873];
    const map = L.map(mapRef.current).setView(center, 12);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '© <a href="https://openstreetmap.org">OpenStreetMap</a> contributors'
    }).addTo(map);

    if (userLocation) {
      const userIcon = L.divIcon({
        className: '',
        html: `<div style="width:18px;height:18px;background:#4895ef;border:3px solid white;border-radius:50%;box-shadow:0 2px 8px rgba(0,0,0,0.4)"></div>`,
        iconSize: [18,18], iconAnchor: [9,9]
      });
      L.marker([userLocation.lat, userLocation.lng], { icon: userIcon })
        .addTo(map).bindPopup('<b>📍 Your Location</b>');
    }
    mapInstance.current = map;
    updateMarkers();
  };

  const updateMarkers = () => {
    if (!window.L || !mapInstance.current) return;
    const L = window.L;
    markersRef.current.forEach(m => m.marker.remove());
    markersRef.current = [];

    filtered.forEach(hospital => {
      if (!hospital.latitude || !hospital.longitude) return;
      const color = TYPE_COLORS[hospital.hospital_type] || '#666';
      const emoji = TYPE_EMOJI[hospital.hospital_type] || '🏥';
      const isSelected = selectedHospital?.id === hospital.id;

      const icon = L.divIcon({
        className: '',
        html: `<div style="
          width:${isSelected ? 42 : 34}px;height:${isSelected ? 42 : 34}px;
          background:${color};border:${isSelected ? '3px' : '2px'} solid white;
          border-radius:50%;display:flex;align-items:center;justify-content:center;
          font-size:${isSelected ? 18 : 15}px;
          box-shadow:0 3px ${isSelected ? 16 : 10}px rgba(0,0,0,${isSelected ? 0.5 : 0.3});
          cursor:pointer;transition:all 0.2s;
        ">${emoji}</div>`,
        iconSize: isSelected ? [42,42] : [34,34],
        iconAnchor: isSelected ? [21,21] : [17,17]
      });

      const marker = L.marker(
        [parseFloat(hospital.latitude), parseFloat(hospital.longitude)], { icon }
      ).addTo(mapInstance.current);

      marker.on('click', () => {
        setSelectedHospital(hospital);
        setRouteInfo(null);
        setSteps([]);
        setShowDirections(false);
        clearRoute();
      });

      markersRef.current.push({ marker, hospital });
    });
  };

  const clearRoute = () => {
    if (!mapInstance.current) return;
    if (routeLayerRef.current) { routeLayerRef.current.remove(); routeLayerRef.current = null; }
    if (endMarkerRef.current) { endMarkerRef.current.remove(); endMarkerRef.current = null; }
  };

  // ── GET DIRECTIONS using OSRM (free, no API key) ──────────────────
  const getDirections = async (hospital, mode) => {
    if (!userLocation) { alert('Could not get your location. Please allow location access.'); return; }
    if (!hospital.latitude || !hospital.longitude) { alert('Hospital location not available.'); return; }

    setRouteLoading(true);
    setRouteInfo(null);
    setSteps([]);
    clearRoute();

    try {
      const osrmProfile = TRAVEL_MODES.find(m => m.key === mode)?.osrm || 'driving';
      const url = `https://router.project-osrm.org/route/v1/${osrmProfile}/${userLocation.lng},${userLocation.lat};${hospital.longitude},${hospital.latitude}?overview=full&geometries=geojson&steps=true&annotations=false`;

      const res = await fetch(url);
      const data = await res.json();

      if (data.code !== 'Ok' || !data.routes?.length) {
        alert('Could not find route. Please try another travel mode.');
        setRouteLoading(false);
        return;
      }

      const route = data.routes[0];
      const distanceKm = (route.distance / 1000).toFixed(1);
      const durationMin = Math.ceil(route.duration / 60);
      const hours = Math.floor(durationMin / 60);
      const mins = durationMin % 60;
      const durationStr = hours > 0 ? `${hours}h ${mins}m` : `${mins} min`;

      setRouteInfo({ distance: distanceKm, duration: durationStr, mode });

      // Extract turn-by-turn steps
      const allSteps = [];
      route.legs?.forEach(leg => {
        leg.steps?.forEach(step => {
          if (step.maneuver?.type && step.name) {
            allSteps.push({
              instruction: getStepInstruction(step),
              distance: step.distance > 1000
                ? `${(step.distance/1000).toFixed(1)} km`
                : `${Math.round(step.distance)} m`,
            });
          }
        });
      });
      setSteps(allSteps);
      setShowDirections(true);

      // Draw route on map
      if (mapInstance.current && window.L) {
        const L = window.L;
        const coords = route.geometry.coordinates.map(c => [c[1], c[0]]);

        routeLayerRef.current = L.polyline(coords, {
          color: '#4895ef',
          weight: 5,
          opacity: 0.85,
          dashArray: osrmProfile === 'foot' ? '8,8' : null,
        }).addTo(mapInstance.current);

        // Hospital destination marker (pulsing)
        const destIcon = L.divIcon({
          className: '',
          html: `<div style="position:relative">
            <div style="width:20px;height:20px;background:#e63946;border:3px solid white;border-radius:50%;box-shadow:0 2px 10px rgba(230,57,70,0.6);z-index:2;position:relative"></div>
            <div style="position:absolute;top:0;left:0;width:20px;height:20px;background:#e63946;border-radius:50%;opacity:0.4;animation:pulse 1.5s infinite"></div>
          </div>`,
          iconSize: [20,20], iconAnchor: [10,10]
        });
        endMarkerRef.current = L.marker(
          [parseFloat(hospital.latitude), parseFloat(hospital.longitude)],
          { icon: destIcon }
        ).addTo(mapInstance.current).bindPopup(`<b>🏥 ${hospital.name}</b>`).openPopup();

        // Fit map to route
        mapInstance.current.fitBounds(routeLayerRef.current.getBounds(), { padding: [40, 40] });
      }
    } catch (err) {
      alert('Failed to get directions. Please check your internet connection.');
    } finally {
      setRouteLoading(false);
    }
  };

  const getStepInstruction = (step) => {
    const type = step.maneuver?.type || '';
    const modifier = step.maneuver?.modifier || '';
    const name = step.name || 'the road';

    const instructions = {
      'depart': `Start on ${name}`,
      'arrive': `Arrive at destination`,
      'turn':   `Turn ${modifier} onto ${name}`,
      'continue': `Continue onto ${name}`,
      'roundabout': `Enter roundabout, take exit onto ${name}`,
      'merge':  `Merge onto ${name}`,
      'ramp':   `Take ramp onto ${name}`,
      'fork':   `Keep ${modifier} at fork onto ${name}`,
    };
    return instructions[type] || `${type} ${modifier} onto ${name}`;
  };

  const applyFilters = () => {
    let result = [...hospitals];
    if (search) {
      const s = search.toLowerCase();
      result = result.filter(h =>
        h.name.toLowerCase().includes(s) ||
        (h.area||'').toLowerCase().includes(s) ||
        (h.specializations||'').toLowerCase().includes(s)
      );
    }
    if (typeFilter !== 'All') result = result.filter(h => h.hospital_type === typeFilter);
    if (emergencyOnly) result = result.filter(h => h.has_emergency);
    setFiltered(result);
  };

  const focusHospital = (hospital) => {
    setSelectedHospital(hospital);
    setRouteInfo(null);
    setSteps([]);
    setShowDirections(false);
    clearRoute();
    if (!mapInstance.current || !hospital.latitude) return;
    mapInstance.current.setView([parseFloat(hospital.latitude), parseFloat(hospital.longitude)], 15);
    const found = markersRef.current.find(m => m.hospital.id === hospital.id);
    if (found) found.marker.openPopup();
  };

  const hospitalTypes = ['All','Government','Super Specialty','Multi Specialty','Private','Nursing Home','Clinic'];

  return (
    <div className="animate-fade">
      <style>{`
        @keyframes pulse { 0%,100%{transform:scale(1);opacity:0.4} 50%{transform:scale(2);opacity:0} }
      `}</style>

      <div style={{ marginBottom: 20 }}>
        <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 28, marginBottom: 4 }}>🗺️ Nearby Hospitals</h1>
        <p style={{ color: 'var(--text-muted)' }}>{filtered.length} hospitals · Click any hospital then get directions</p>
      </div>

      {/* Filters */}
      <div className="card" style={{ marginBottom: 16 }}>
        <div className="card-body" style={{ padding: '14px 20px' }}>
          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', alignItems: 'center' }}>
            <input className="form-control" style={{ maxWidth: 240 }} placeholder="🔎 Search hospital or area..." value={search} onChange={e => setSearch(e.target.value)} />
            <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
              {hospitalTypes.map(t => (
                <button key={t} className={`btn btn-sm ${typeFilter === t ? 'btn-primary' : 'btn-outline'}`} onClick={() => setTypeFilter(t)}>
                  {TYPE_EMOJI[t] || '🏥'} {t}
                </button>
              ))}
            </div>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 14, cursor: 'pointer' }}>
              <input type="checkbox" checked={emergencyOnly} onChange={e => setEmergencyOnly(e.target.checked)} />
              🚨 Emergency Only
            </label>
          </div>
        </div>
      </div>

      {/* Legend */}
      <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', marginBottom: 14 }}>
        {Object.entries(TYPE_COLORS).map(([type, color]) => (
          <div key={type} style={{ display: 'flex', alignItems: 'center', gap: 5, fontSize: 12 }}>
            <div style={{ width: 11, height: 11, borderRadius: '50%', background: color }} />{type}
          </div>
        ))}
      </div>

      {/* Main grid */}
      <div style={{ display: 'grid', gridTemplateColumns: '300px 1fr', gap: 16, alignItems: 'start' }}>

        {/* Hospital list */}
        <div className="card" style={{ maxHeight: 580, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
          <div className="card-header" style={{ flexShrink: 0 }}><h2>Hospitals ({filtered.length})</h2></div>
          <div style={{ overflowY: 'auto', flex: 1 }}>
            {loading ? <div className="loading-center"><div className="spinner" /></div>
            : filtered.length === 0 ? <div className="empty-state"><div className="empty-icon">🏥</div><h3>No hospitals found</h3></div>
            : filtered.map(h => (
              <div key={h.id} onClick={() => focusHospital(h)} style={{
                padding: '12px 14px', borderBottom: '1px solid var(--border)', cursor: 'pointer',
                background: selectedHospital?.id === h.id ? 'var(--success-light)' : 'white',
                borderLeft: selectedHospital?.id === h.id ? '3px solid var(--primary)' : '3px solid transparent',
                transition: 'all 0.15s'
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 600, fontSize: 13, marginBottom: 3, lineHeight: 1.3 }}>{h.name}</div>
                    <span style={{ padding: '1px 7px', borderRadius: 99, fontSize: 10, fontWeight: 600, background: (TYPE_COLORS[h.hospital_type]||'#666')+'22', color: TYPE_COLORS[h.hospital_type]||'#666' }}>{h.hospital_type}</span>
                    <div style={{ fontSize: 11, color: 'var(--text-muted)', marginTop: 4 }}>📍 {h.area}</div>
                    <div style={{ display: 'flex', gap: 8, marginTop: 3, fontSize: 11 }}>
                      {h.has_emergency && <span style={{ color: '#e63946' }}>🚨 ER</span>}
                      {h.has_icu && <span style={{ color: '#4895ef' }}>🏥 ICU</span>}
                      {h.has_ambulance && <span style={{ color: '#2d6a4f' }}>🚑</span>}
                    </div>
                  </div>
                  <div style={{ fontSize: 11, color: '#f4a261', fontWeight: 600 }}>⭐{h.rating}</div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Map + Direction panel */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          <div ref={mapRef} style={{ height: 480, borderRadius: 'var(--radius)', overflow: 'hidden', border: '1px solid var(--border)' }} />

          {/* Direction panel — shows when hospital is selected */}
          {selectedHospital && (
            <div className="card animate-slide">
              <div className="card-body">
                {/* Hospital name + info */}
                <div style={{ display: 'flex', gap: 12, alignItems: 'flex-start', marginBottom: 16 }}>
                  <span style={{ fontSize: 28 }}>{TYPE_EMOJI[selectedHospital.hospital_type]||'🏥'}</span>
                  <div style={{ flex: 1 }}>
                    <h3 style={{ fontSize: 16, fontWeight: 700, marginBottom: 2 }}>{selectedHospital.name}</h3>
                    <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>📍 {selectedHospital.address}</div>
                    <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>📞 {selectedHospital.phone} · ⏰ {selectedHospital.timings}</div>
                  </div>
                  <button className="btn btn-outline btn-sm" onClick={() => { setSelectedHospital(null); clearRoute(); setRouteInfo(null); setSteps([]); setShowDirections(false); }}>✕</button>
                </div>

                {/* Travel mode selector + Get Directions button */}
                <div style={{ display: 'flex', gap: 10, alignItems: 'center', flexWrap: 'wrap', marginBottom: 12 }}>
                  <span style={{ fontSize: 13, fontWeight: 600, color: 'var(--text-muted)' }}>Travel by:</span>
                  {TRAVEL_MODES.map(m => (
                    <button key={m.key}
                      className={`btn btn-sm ${travelMode === m.key ? 'btn-primary' : 'btn-outline'}`}
                      onClick={() => setTravelMode(m.key)}>
                      {m.label}
                    </button>
                  ))}
                  <button
                    className="btn btn-accent"
                    onClick={() => getDirections(selectedHospital, travelMode)}
                    disabled={routeLoading}
                    style={{ marginLeft: 'auto' }}>
                    {routeLoading ? '⏳ Finding route...' : '🧭 Get Directions'}
                  </button>
                  {routeInfo && (
                    <button className="btn btn-outline btn-sm" onClick={() => { clearRoute(); setRouteInfo(null); setSteps([]); setShowDirections(false); }}>
                      🗑️ Clear Route
                    </button>
                  )}
                </div>

                {/* Route summary */}
                {routeInfo && (
                  <div style={{ display: 'flex', gap: 16, padding: '12px 16px', background: 'var(--success-light)', borderRadius: 10, marginBottom: showDirections ? 12 : 0 }}>
                    <div style={{ textAlign: 'center' }}>
                      <div style={{ fontSize: 22, fontWeight: 700, color: 'var(--primary)' }}>{routeInfo.distance} km</div>
                      <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>Distance</div>
                    </div>
                    <div style={{ width: 1, background: 'var(--border)' }} />
                    <div style={{ textAlign: 'center' }}>
                      <div style={{ fontSize: 22, fontWeight: 700, color: 'var(--primary)' }}>{routeInfo.duration}</div>
                      <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>Estimated Time</div>
                    </div>
                    <div style={{ width: 1, background: 'var(--border)' }} />
                    <div style={{ textAlign: 'center' }}>
                      <div style={{ fontSize: 22, fontWeight: 700, color: 'var(--primary)' }}>
                        {TRAVEL_MODES.find(m => m.key === routeInfo.mode)?.label}
                      </div>
                      <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>Mode</div>
                    </div>
                    <div style={{ marginLeft: 'auto', display: 'flex', alignItems: 'center' }}>
                      <button className="btn btn-outline btn-sm" onClick={() => setShowDirections(!showDirections)}>
                        {showDirections ? '▲ Hide Steps' : '▼ Turn-by-Turn'}
                      </button>
                    </div>
                  </div>
                )}

                {/* Turn-by-turn steps */}
                {showDirections && steps.length > 0 && (
                  <div style={{ maxHeight: 220, overflowY: 'auto', border: '1px solid var(--border)', borderRadius: 10 }}>
                    {steps.map((step, i) => (
                      <div key={i} style={{
                        display: 'flex', gap: 12, padding: '10px 14px',
                        borderBottom: i < steps.length - 1 ? '1px solid var(--border)' : 'none',
                        background: i === 0 || i === steps.length - 1 ? 'var(--bg)' : 'white',
                      }}>
                        <div style={{
                          width: 26, height: 26, borderRadius: '50%', flexShrink: 0,
                          background: i === 0 ? '#4895ef' : i === steps.length - 1 ? '#e63946' : 'var(--border)',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          fontSize: 12, color: i < steps.length - 1 && i > 0 ? 'var(--text-muted)' : 'white', fontWeight: 700
                        }}>
                          {i === 0 ? '📍' : i === steps.length - 1 ? '🏥' : i}
                        </div>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontSize: 13, fontWeight: 500 }}>{step.instruction}</div>
                          <div style={{ fontSize: 11, color: 'var(--text-muted)', marginTop: 2 }}>{step.distance}</div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
